hazard:
display: flex; align-items: center; gap: 6px;
    padding: 6px 10px;
    border-radius: 14px;
    color: #fff;
    font-weight: 700;
    font-size: 12px;

puck-pulse:
position: absolute;
    inset: 10px;
    border-radius: 50%;
    background: var(--cyan);
    opacity: 0.15;
    animation: puck-pulse 2s ease-out infinite;

nt-arrow:
width: 56px; height: 56px;
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;

sl-circle:
width: 34px; height: 34px;
    border-radius: 50%;
    background: #fff;
    border: 2px solid var(--ink);
    display: flex; align-items: center; justify-content: center;
    font-size: 16px;
    font-weight: 700;
    font-variant-numeric: tabular-nums;
